#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.contraptionTimeoutFade)]
    public class ContraptionTimeoutFadeBehaviour : EntityBehaviourDefinition
    {
        public ContraptionTimeoutFadeBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity contraption)
        {
            base.Init(contraption);
            contraption.Timeout = contraption.GetMaxTimeout();
        }
        public override void Update(Entity contraption)
        {
            base.Update(contraption);
            contraption.Timeout--;
            var tint = contraption.GetTint();
            tint.a = contraption.Timeout / (float)contraption.GetMaxTimeout();
            contraption.SetTint(tint);
            if (contraption.Timeout <= 0)
            {
                contraption.Remove();
            }
        }
    }
}
